head.b:skin:
/*
============================================
Baby Name Ideas - Blogger Theme
Design: Modern Parenting Magazine
Colors: Primary #FF7A8A | Secondary #FFF5F6 | Accent #FFB6C1
Typography: Inter + Poppins
============================================
*/

/* ========== RESET & BASE ========== */
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth;-webkit-text-size-adjust:100%}
body{
  font-family:'Inter','Poppins',-apple-system,BlinkMacSystemFont,sans-serif;
  font-size:16px;
  line-height:1.625;
  color:#333;
  background:#fff;
  -webkit-font-smoothing:antialiased;
  -moz-osx-font-smoothing:grayscale;
  overflow-x:hidden;
}
img{max-width:100%;height:auto;display:block}
a{color:#FF7A8A;text-decoration:none;transition:color .2s}
a:hover{color:#e85d6e}
h1,h2,h3,h4,h5,h6{font-family:'Poppins',sans-serif;color:#333;line-height:1.3}
h1{font-size:2rem;font-weight:800}
h2{font-size:1.625rem;font-weight:700;margin:2rem 0 1rem}
h3{font-size:1.25rem;font-weight:600;margin:1.5rem 0 .75rem}
h4{font-size:1.1rem;font-weight:600}
p{margin-bottom:1rem}
ul,ol{margin:0 0 1rem 1.5rem}
blockquote{border-left:4px solid #FFB6C1;margin:1.5rem 0;padding:.5rem 1.5rem;background:#FFF5F6;border-radius:0 12px 12px 0}
table{width:100%;border-collapse:collapse;margin:1.5rem 0;font-size:.925rem}
thead{background:#FFF5F6}
th{padding:12px 16px;text-align:left;font-weight:600;color:#333;font-size:.85rem}
td{padding:10px 16px;border-bottom:1px solid #f0f0f0}
tr:hover td{background:rgba(255,122,138,.04)}
button{cursor:pointer;font-family:inherit}

/* ========== LAYOUT ========== */
.container{max-width:1200px;margin:0 auto;padding:0 20px}
.row{display:flex;flex-wrap:wrap;gap:24px}
.main-content{flex:1 1 100%;max-width:100%}

/* ========== HEADER ========== */
.site-header{
  background:#fff;
  border-bottom:1px solid #f0f0f0;
  position:sticky;
  top:0;
  z-index:100;
  backdrop-filter:blur(8px);
  -webkit-backdrop-filter:blur(8px);
}
.header-inner{
  max-width:1200px;
  margin:0 auto;
  padding:0 20px;
  display:flex;
  align-items:center;
  justify-content:space-between;
  height:66px;
}
.site-branding{
  display:flex;
  align-items:center;
  gap:10px;
  flex-shrink:0;
}
.site-logo{
  font-size:1.75rem;
}
.site-title{
  font-family:'Poppins',sans-serif;
  font-size:1.3rem;
  font-weight:800;
  color:#FF7A8A;
  text-decoration:none;
  white-space:nowrap;
}
.site-title:hover{color:#FF7A8A}
.site-description{
  display:none;
}

/* ========== NAVIGATION ========== */
.main-nav{display:flex;align-items:center;gap:2px}
.main-nav a{
  display:inline-flex;
  align-items:center;
  padding:8px 14px;
  font-size:.875rem;
  font-weight:500;
  color:#555;
  border-radius:8px;
  transition:all .2s;
  white-space:nowrap;
}
.main-nav a:hover{
  color:#FF7A8A;
  background:#FFF5F6;
}
.nav-toggle{
  display:none;
  background:none;
  border:none;
  font-size:1.5rem;
  color:#333;
  padding:8px;
  cursor:pointer;
}

/* ========== HERO SECTION ========== */
.hero-section{
  background:linear-gradient(180deg,#FFF5F6 0%,#fff 100%);
  padding:48px 20px 40px;
  text-align:center;
}
.hero-inner{max-width:720px;margin:0 auto}
.hero-title{
  font-family:'Poppins',sans-serif;
  font-size:2.5rem;
  font-weight:800;
  color:#FF7A8A;
  margin-bottom:12px;
  line-height:1.15;
}
.hero-subtitle{
  font-size:1.15rem;
  color:#777;
  margin-bottom:28px;
  max-width:540px;
  margin-left:auto;
  margin-right:auto;
}
.hero-search{
  max-width:500px;
  margin:0 auto;
  position:relative;
}
.hero-search form{display:flex;width:100%}
.hero-search input{
  flex:1;
  padding:14px 20px;
  border:2px solid #FFB6C1;
  border-radius:50px 0 0 50px;
  font-size:1rem;
  outline:none;
  transition:border-color .2s;
  font-family:inherit;
}
.hero-search input:focus{border-color:#FF7A8A}
.hero-search button{
  padding:14px 28px;
  background:#FF7A8A;
  color:#fff;
  border:none;
  border-radius:0 50px 50px 0;
  font-weight:600;
  font-size:.95rem;
  transition:background .2s;
}
.hero-search button:hover{background:#e85d6e}

/* ========== CATEGORY CARDS ========== */
.categories-section{
  padding:48px 20px;
  max-width:1200px;
  margin:0 auto;
}
.section-title{
  font-family:'Poppins',sans-serif;
  font-size:1.75rem;
  font-weight:700;
  text-align:center;
  margin-bottom:32px;
  color:#333;
}
.category-grid{
  display:grid;
  grid-template-columns:repeat(auto-fill,minmax(200px,1fr));
  gap:14px;
}
.category-card{
  background:#fff;
  border:1px solid #eee;
  border-radius:16px;
  padding:22px 18px;
  text-align:center;
  transition:all .25s;
  text-decoration:none;
  display:block;
}
.category-card:hover{
  border-color:#FF7A8A;
  box-shadow:0 8px 30px rgba(255,122,138,.12);
  transform:translateY(-2px);
}
.category-card-icon{
  font-size:2rem;
  margin-bottom:8px;
  display:block;
}
.category-card-name{
  font-family:'Poppins',sans-serif;
  font-weight:600;
  font-size:.9rem;
  color:#333;
  margin-bottom:4px;
}
.category-card-desc{
  font-size:.775rem;
  color:#999;
  line-height:1.4;
}

/* ========== FEATURED SECTION ========== */
.featured-section{
  padding:0 20px 48px;
  max-width:1200px;
  margin:0 auto;
}
.featured-grid{
  display:grid;
  grid-template-columns:repeat(auto-fill,minmax(340px,1fr));
  gap:20px;
}
.featured-card{
  background:#fff;
  border:1px solid #eee;
  border-radius:16px;
  overflow:hidden;
  transition:all .25s;
}
.featured-card:hover{
  border-color:#FF7A8A;
  box-shadow:0 12px 40px rgba(255,122,138,.1);
  transform:translateY(-3px);
}
.featured-card-image{
  height:180px;
  background:linear-gradient(135deg,#FFB6C1,#FFF5F6);
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:3rem;
}
.featured-card-body{padding:20px}
.featured-card-labels{
  display:flex;
  flex-wrap:wrap;
  gap:6px;
  margin-bottom:10px;
}
.featured-card-label{
  font-size:.7rem;
  font-weight:600;
  padding:3px 10px;
  border-radius:50px;
  background:#FFF5F6;
  color:#FF7A8A;
}
.featured-card-title{
  font-family:'Poppins',sans-serif;
  font-weight:600;
  font-size:1.05rem;
  margin-bottom:8px;
  line-height:1.35;
}
.featured-card-title a{color:#333}
.featured-card-title a:hover{color:#FF7A8A}
.featured-card-excerpt{
  font-size:.85rem;
  color:#888;
  line-height:1.5;
  display:-webkit-box;
  -webkit-line-clamp:2;
  -webkit-box-orient:vertical;
  overflow:hidden;
}
.featured-card-meta{
  font-size:.75rem;
  color:#bbb;
  margin-top:10px;
}

/* ========== POSTS GRID ========== */
.posts-section{
  padding:0 20px 48px;
  max-width:1200px;
  margin:0 auto;
}
.posts-grid{
  display:grid;
  grid-template-columns:repeat(auto-fill,minmax(300px,1fr));
  gap:20px;
}
.post-card{
  background:#fff;
  border:1px solid #eee;
  border-radius:16px;
  overflow:hidden;
  transition:all .25s;
}
.post-card:hover{
  border-color:#FFB6C1;
  box-shadow:0 8px 30px rgba(0,0,0,.06);
}
.post-card-image{
  height:160px;
  background:linear-gradient(135deg,#FFF5F6,#FFE0E5);
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:2.5rem;
}
.post-card-body{padding:18px}
.post-card-labels{
  display:flex;
  flex-wrap:wrap;
  gap:5px;
  margin-bottom:8px;
}
.post-card-label{
  font-size:.65rem;
  font-weight:600;
  padding:2px 8px;
  border-radius:50px;
  background:#FFF5F6;
  color:#FF7A8A;
}
.post-card-title{
  font-family:'Poppins',sans-serif;
  font-weight:600;
  font-size:.95rem;
  line-height:1.35;
  margin-bottom:6px;
}
.post-card-title a{color:#333}
.post-card-title a:hover{color:#FF7A8A}
.post-card-excerpt{
  font-size:.8rem;
  color:#999;
  line-height:1.5;
  display:-webkit-box;
  -webkit-line-clamp:2;
  -webkit-box-orient:vertical;
  overflow:hidden;
}
.post-card-date{font-size:.7rem;color:#ccc;margin-top:8px}

/* ========== POST PAGE ========== */
.post-single{
  max-width:780px;
  margin:0 auto;
  padding:32px 20px;
}
.breadcrumbs{
  font-size:.8rem;
  color:#aaa;
  margin-bottom:20px;
}
.breadcrumbs a{color:#999;text-decoration:none}
.breadcrumbs a:hover{color:#FF7A8A}
.post-header{margin-bottom:24px}
.post-labels{
  display:flex;
  flex-wrap:wrap;
  gap:7px;
  margin-bottom:12px;
}
.post-label{
  font-size:.75rem;
  font-weight:600;
  padding:4px 12px;
  border-radius:50px;
  background:#FFF5F6;
  color:#FF7A8A;
}
.post-title{
  font-family:'Poppins',sans-serif;
  font-size:2rem;
  font-weight:800;
  color:#333;
  line-height:1.2;
  margin-bottom:12px;
}
.post-meta{
  font-size:.85rem;
  color:#aaa;
}
.post-body{
  font-size:1.05rem;
  line-height:1.75;
  color:#444;
}
.post-body h2{
  font-size:1.5rem;
  margin:2.5rem 0 1rem;
  padding-bottom:.5rem;
  border-bottom:2px solid #FFF5F6;
}
.post-body h3{font-size:1.2rem;margin:2rem 0 .75rem}
.post-body img{border-radius:12px;margin:1.5rem auto}
.post-body a{font-weight:500;text-decoration:underline;text-underline-offset:3px}
.post-body table{
  border:1px solid #eee;
  border-radius:12px;
  overflow:hidden;
  box-shadow:0 2px 8px rgba(0,0,0,.03);
}
.post-body blockquote{
  font-style:italic;
  font-size:1.05rem;
}
.post-footer{
  margin-top:40px;
  padding-top:24px;
  border-top:1px solid #f0f0f0;
}
.author-box{
  display:flex;
  align-items:center;
  gap:14px;
  padding:20px;
  background:#FFF5F6;
  border-radius:16px;
  margin-bottom:24px;
}
.author-avatar{
  width:48px;
  height:48px;
  border-radius:50%;
  background:#FF7A8A;
  display:flex;
  align-items:center;
  justify-content:center;
  color:#fff;
  font-weight:700;
  font-size:1.25rem;
  flex-shrink:0;
}
.author-info-name{font-weight:600;color:#333;font-size:.9rem}
.author-info-bio{font-size:.8rem;color:#888;margin-top:2px}

/* ========== FAQ ACCORDION ========== */
.faq-section{margin:2rem 0}
.faq-item{
  border:1px solid #eee;
  border-radius:12px;
  margin-bottom:10px;
  overflow:hidden;
}
.faq-question{
  padding:16px 20px;
  cursor:pointer;
  font-weight:500;
  display:flex;
  justify-content:space-between;
  align-items:center;
  background:#fff;
  transition:background .2s;
}
.faq-question:hover{background:#FFF5F6}
.faq-toggle{
  font-size:1.25rem;
  color:#FF7A8A;
  transition:transform .2s;
  flex-shrink:0;
  margin-left:12px;
}
.faq-answer{
  padding:0 20px 16px;
  font-size:.95rem;
  color:#666;
  display:none;
}
.faq-open .faq-question{background:#FFF5F6}
.faq-open .faq-toggle{transform:rotate(45deg)}
.faq-open .faq-answer{display:block}

/* ========== SIDEBAR ========== */
.sidebar{
  background:#fff;
  border-radius:16px;
}
.sidebar-section{
  margin-bottom:24px;
  padding:20px;
  background:#fff;
  border:1px solid #f0f0f0;
  border-radius:16px;
}
.sidebar-title{
  font-family:'Poppins',sans-serif;
  font-size:1rem;
  font-weight:700;
  color:#333;
  margin-bottom:14px;
  padding-bottom:10px;
  border-bottom:2px solid #FFF5F6;
}
.sidebar ul{list-style:none;margin:0;padding:0}
.sidebar li{margin-bottom:8px}
.sidebar a{
  color:#666;
  font-size:.875rem;
  transition:color .2s;
  display:block;
  padding:4px 0;
}
.sidebar a:hover{color:#FF7A8A}

/* Popular posts widget styling */
.PopularPosts .item-title{
  font-size:.875rem;
  font-weight:600;
  line-height:1.4;
  padding-bottom:0;
}

/* Labels widget */
.Label li{
  display:inline-block;
  margin:0 5px 8px 0;
}
.Label a{
  background:#FFF5F6;
  color:#FF7A8A;
  padding:5px 12px;
  border-radius:50px;
  font-size:.75rem;
  font-weight:500;
}
.Label a:hover{background:#FF7A8A;color:#fff}

/* ========== PAGINATION ========== */
.blog-pager{
  text-align:center;
  padding:32px 0;
  clear:both;
}
.blog-pager a,.blog-pager span{
  display:inline-block;
  padding:10px 20px;
  margin:0 4px;
  border-radius:50px;
  font-size:.875rem;
  font-weight:500;
  transition:all .2s;
}
.blog-pager a{
  background:#FFF5F6;
  color:#FF7A8A;
}
.blog-pager a:hover{background:#FF7A8A;color:#fff}
.blog-pager .current{
  background:#FF7A8A;
  color:#fff;
}
.blog-pager .blog-pager-older-link,
.blog-pager .blog-pager-newer-link{
  float:none;
}

/* ========== NEWSLETTER ========== */
.newsletter-section{
  background:#FFF5F6;
  padding:48px 20px;
  text-align:center;
}
.newsletter-inner{max-width:480px;margin:0 auto}
.newsletter-title{
  font-family:'Poppins',sans-serif;
  font-size:1.5rem;
  font-weight:700;
  margin-bottom:8px;
}
.newsletter-desc{font-size:.9rem;color:#888;margin-bottom:20px}
.newsletter-form{display:flex;gap:8px}
.newsletter-form input{
  flex:1;
  padding:12px 18px;
  border:2px solid #FFB6C1;
  border-radius:50px;
  font-size:.9rem;
  outline:none;
  font-family:inherit;
}
.newsletter-form button{
  padding:12px 24px;
  background:#FF7A8A;
  color:#fff;
  border:none;
  border-radius:50px;
  font-weight:600;
  font-size:.9rem;
}

/* ========== FOOTER ========== */
.site-footer{
  background:#fff;
  border-top:1px solid #f0f0f0;
  padding:48px 20px 24px;
}
.footer-inner{
  max-width:1200px;
  margin:0 auto;
  display:grid;
  grid-template-columns:repeat(auto-fit,minmax(220px,1fr));
  gap:32px;
}
.footer-col-title{
  font-family:'Poppins',sans-serif;
  font-size:.85rem;
  font-weight:700;
  color:#333;
  text-transform:uppercase;
  letter-spacing:.5px;
  margin-bottom:16px;
}
.footer-col ul{list-style:none;margin:0;padding:0}
.footer-col li{margin-bottom:6px}
.footer-col a{
  font-size:.85rem;
  color:#888;
  transition:color .2s;
}
.footer-col a:hover{color:#FF7A8A}
.footer-brand{font-size:1rem}
.footer-brand .site-title{font-size:1.2rem;margin-bottom:6px}
.footer-brand-desc{
  font-size:.8rem;
  color:#aaa;
  line-height:1.5;
  margin-top:6px;
}
.footer-bottom{
  max-width:1200px;
  margin:32px auto 0;
  padding-top:20px;
  border-top:1px solid #f0f0f0;
  text-align:center;
  font-size:.75rem;
  color:#bbb;
}

/* ========== RESPONSIVE ========== */
@media (min-width:769px){
  .has-sidebar .main-content{flex:1 1 68%;max-width:68%}
  .has-sidebar .sidebar{flex:0 0 30%}
}

@media (max-width:768px){
  .site-title{font-size:1.1rem}
  .main-nav{
    position:fixed;
    top:66px;
    left:0;
    right:0;
    background:#fff;
    flex-direction:column;
    padding:12px;
    border-bottom:1px solid #f0f0f0;
    display:none;
    box-shadow:0 8px 20px rgba(0,0,0,.08);
  }
  .main-nav.open{display:flex}
  .main-nav a{padding:12px 16px;width:100%;border-radius:0}
  .nav-toggle{display:block}
  .hero-title{font-size:1.75rem}
  .hero-subtitle{font-size:1rem}
  .category-grid{grid-template-columns:repeat(3,1fr);gap:8px}
  .category-card{padding:14px 10px}
  .category-card-name{font-size:.75rem}
  .featured-grid{grid-template-columns:1fr}
  .posts-grid{grid-template-columns:1fr}
  .post-title{font-size:1.5rem}
  .footer-inner{grid-template-columns:repeat(2,1fr)}
  .newsletter-form{flex-direction:column}
}

@media (max-width:480px){
  .header-inner{height:56px}
  .site-title{font-size:1rem}
  .hero-section{padding:32px 16px 28px}
  .hero-title{font-size:1.4rem}
  .hero-search input{padding:12px 16px;font-size:.9rem}
  .hero-search button{padding:12px 18px;font-size:.85rem}
  .category-grid{grid-template-columns:repeat(2,1fr)}
  .section-title{font-size:1.3rem}
  .footer-inner{grid-template-columns:1fr}
}

/* ========== PRINT ========== */
@media print{
  .site-header,.site-footer,.sidebar,.hero-section,.categories-section{display:none}
  .post-single{max-width:100%}
  body{font-size:12pt}
}

body.script:
//
(function(){
  document.addEventListener('click', function(e){
    var q = e.target.closest('.faq-question');
    if(q){
      var item = q.parentNode;
      item.classList.toggle('faq-open');
    }
  });
})();
//

//
(function(){
  var t = document.querySelector('.nav-toggle');
  if(t){
    t.addEventListener('click', function(){
      document.querySelector('.main-nav').classList.toggle('open');
    });
  }
})();
//
